static inline float quantile_scale(int feature_idx, float x)
{
    if (feature_idx < 0 || feature_idx >= QT_N_FEATURES)
        return x;

    const float* qs = QT_QUANTILES[feature_idx];

    if (x <= qs[0])
        return QT_REFERENCES[0];

    if (x >= qs[QT_N_QUANTILES - 1])
        return QT_REFERENCES[QT_N_QUANTILES - 1];

    int lo = 0;
    int hi = QT_N_QUANTILES - 1;

    while (hi - lo > 1)
    {
        int mid = (lo + hi) / 2;
        if (qs[mid] <= x)
            lo = mid;
        else
            hi = mid;
    }

    float q0 = qs[lo];
    float q1 = qs[hi];
    float r0 = QT_REFERENCES[lo];
    float r1 = QT_REFERENCES[hi];

    if (std::fabs(q1 - q0) < 1e-12f)
        return r0;

    float t = (x - q0) / (q1 - q0);
    return r0 + t * (r1 - r0);
}
